RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(procedure_version, '') FROM procedure_status_changes WHERE procedure_status_change_id = p_procedure_status_change_id), ': ', (SELECT NULLIF(from_status, '') FROM procedure_status_changes WHERE procedure_status_change_id = p_procedure_status_change_id), ' -> ', (SELECT NULLIF(to_status, '') FROM procedure_status_changes WHERE procedure_status_change_id = p_procedure_status_change_id)))::text;
