CREATE OR REPLACE FUNCTION calc_steps_assigned_role_label(p_step_id TEXT)
RETURNS TEXT AS $$
  SELECT (SELECT label::text FROM roles WHERE role_id = (SELECT assigned_role FROM steps WHERE step_id = p_step_id));
