-- calc_step_requirements_name
-- Field: StepRequirements.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_step_requirements_name(p_step_requirement_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(step, '') FROM step_requirements WHERE step_requirement_id = p_step_requirement_id), ' / ', (SELECT NULLIF(requirement, '') FROM step_requirements WHERE step_requirement_id = p_step_requirement_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_step_requirements_blocking_step_key
-- Field: StepRequirements.BlockingStepKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_step_requirements_blocking_step_key(p_step_requirement_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_step_requirements_requirement_is_blocking(p_step_requirement_id) THEN ((SELECT NULLIF(step, '') FROM step_requirements WHERE step_requirement_id = p_step_requirement_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

