-- calc_knowledge_fragments_name
-- Field: KnowledgeFragments.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_knowledge_fragments_name(p_knowledge_fragment_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(knowledge_form, '') FROM knowledge_fragments WHERE knowledge_fragment_id = p_knowledge_fragment_id), ': ', LEFT(((SELECT NULLIF(statement, '') FROM knowledge_fragments WHERE knowledge_fragment_id = p_knowledge_fragment_id))::text, (60)::integer)))::text;
$$ LANGUAGE sql STABLE;

-- calc_knowledge_fragments_is_currently_valid
-- Field: KnowledgeFragments.IsCurrentlyValid
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_knowledge_fragments_is_currently_valid(p_knowledge_fragment_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT valid_from::timestamptz FROM knowledge_fragments WHERE knowledge_fragment_id = p_knowledge_fragment_id) <= calc_knowledge_fragments_as_of_instant(p_knowledge_fragment_id) AND ((SELECT valid_to::timestamptz FROM knowledge_fragments WHERE knowledge_fragment_id = p_knowledge_fragment_id) IS NULL OR (SELECT valid_to::timestamptz FROM knowledge_fragments WHERE knowledge_fragment_id = p_knowledge_fragment_id) > calc_knowledge_fragments_as_of_instant(p_knowledge_fragment_id)) AND (SELECT NULLIF(status, '') FROM knowledge_fragments WHERE knowledge_fragment_id = p_knowledge_fragment_id) = 'Approved'))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_knowledge_gaps_name
-- Field: KnowledgeGaps.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_knowledge_gaps_name(p_knowledge_gap_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(severity, '') FROM knowledge_gaps WHERE knowledge_gap_id = p_knowledge_gap_id), ': ', LEFT(((SELECT NULLIF(statement, '') FROM knowledge_gaps WHERE knowledge_gap_id = p_knowledge_gap_id))::text, (60)::integer)))::text;
$$ LANGUAGE sql STABLE;

-- calc_knowledge_gaps_is_open
-- Field: KnowledgeGaps.IsOpen
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_knowledge_gaps_is_open(p_knowledge_gap_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT NULLIF(status, '') FROM knowledge_gaps WHERE knowledge_gap_id = p_knowledge_gap_id) = 'Open' OR (SELECT NULLIF(status, '') FROM knowledge_gaps WHERE knowledge_gap_id = p_knowledge_gap_id) = 'Investigating'))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_knowledge_gaps_open_gap_version_key
-- Field: KnowledgeGaps.OpenGapVersionKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_knowledge_gaps_open_gap_version_key(p_knowledge_gap_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN (calc_knowledge_gaps_is_open(p_knowledge_gap_id) AND (SELECT NULLIF(severity, '') FROM knowledge_gaps WHERE knowledge_gap_id = p_knowledge_gap_id) = 'High') THEN ((SELECT NULLIF(procedure_version, '') FROM knowledge_gaps WHERE knowledge_gap_id = p_knowledge_gap_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

