RETURNS BOOLEAN AS $$
  SELECT (SELECT requires_human_confirmation::boolean FROM steps WHERE step_id = (SELECT step FROM step_executions WHERE step_execution_id = p_step_execution_id));
$$ LANGUAGE sql STABLE;

