-- calc_requirement_satisfactions_name
-- Field: RequirementSatisfactions.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_requirement_satisfactions_name(p_requirement_satisfaction_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(requirement, '') FROM requirement_satisfactions WHERE requirement_satisfaction_id = p_requirement_satisfaction_id), ' / ', (SELECT NULLIF(satisfaction_level, '') FROM requirement_satisfactions WHERE requirement_satisfaction_id = p_requirement_satisfaction_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_requirement_satisfactions_is_fully_satisfied
-- Field: RequirementSatisfactions.IsFullySatisfied
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_requirement_satisfactions_is_fully_satisfied(p_requirement_satisfaction_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((SELECT NULLIF(satisfaction_level, '') FROM requirement_satisfactions WHERE requirement_satisfaction_id = p_requirement_satisfaction_id) = 'Satisfied')::boolean;
$$ LANGUAGE sql STABLE;

-- calc_requirement_satisfactions_is_blocking_and_unmet
-- Field: RequirementSatisfactions.IsBlockingAndUnmet
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_requirement_satisfactions_is_blocking_and_unmet(p_requirement_satisfaction_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_requirement_satisfactions_requirement_is_blocking(p_requirement_satisfaction_id) AND NOT (calc_requirement_satisfactions_is_fully_satisfied(p_requirement_satisfaction_id))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_requirement_satisfactions_blocking_unmet_step_key
-- Field: RequirementSatisfactions.BlockingUnmetStepKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_requirement_satisfactions_blocking_unmet_step_key(p_requirement_satisfaction_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_requirement_satisfactions_is_blocking_and_unmet(p_requirement_satisfaction_id) THEN ((SELECT NULLIF(step_execution, '') FROM requirement_satisfactions WHERE requirement_satisfaction_id = p_requirement_satisfaction_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_requirement_satisfactions_blocking_satisfaction_step_key
-- Field: RequirementSatisfactions.BlockingSatisfactionStepKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_requirement_satisfactions_blocking_satisfaction_step_key(p_requirement_satisfaction_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_requirement_satisfactions_requirement_is_blocking(p_requirement_satisfaction_id) THEN ((SELECT NULLIF(step_execution, '') FROM requirement_satisfactions WHERE requirement_satisfaction_id = p_requirement_satisfaction_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_requirement_satisfactions_negative_outcome_requirement_key
-- Field: RequirementSatisfactions.NegativeOutcomeRequirementKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_requirement_satisfactions_negative_outcome_requirement_key(p_requirement_satisfaction_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN NOT (calc_requirement_satisfactions_is_fully_satisfied(p_requirement_satisfaction_id)) THEN ((SELECT NULLIF(requirement, '') FROM requirement_satisfactions WHERE requirement_satisfaction_id = p_requirement_satisfaction_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_requirement_satisfactions_non_human_evaluated_human_contro
-- Field: RequirementSatisfactions.NonHumanEvaluatedHumanControl
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_requirement_satisfactions_non_human_evaluated_human_contro(p_requirement_satisfaction_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_requirement_satisfactions_requirement_is_blocking(p_requirement_satisfaction_id) AND calc_requirement_satisfactions_evaluator_agent_kind(p_requirement_satisfaction_id) <> 'Human'))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_requirement_satisfactions_is_asserted_only
-- Field: RequirementSatisfactions.IsAssertedOnly
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_requirement_satisfactions_is_asserted_only(p_requirement_satisfaction_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_requirement_satisfactions_requirement_is_blocking(p_requirement_satisfaction_id) AND calc_requirement_satisfactions_is_fully_satisfied(p_requirement_satisfaction_id) AND NOT (calc_requirement_satisfactions_requirement_has_computed_witness(p_requirement_satisfaction_id))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_requirement_satisfactions_asserted_only_execution_key
-- Field: RequirementSatisfactions.AssertedOnlyExecutionKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_requirement_satisfactions_asserted_only_execution_key(p_requirement_satisfaction_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_requirement_satisfactions_is_asserted_only(p_requirement_satisfaction_id) THEN (calc_requirement_satisfactions_parent_procedure_execution(p_requirement_satisfaction_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

